def random_balanced_table(N, weight):
    """Random function with given Hamming weight."""
    size = 1 << N
    tt = [0] * size
    ones = random.sample(range(size), min(weight, size))
    for i in ones:
        tt[i] = 1
    return tt


def tt_to_int(tt_list):
    """Convert list truth table to integer bitmask."""
    val = 0
    for i, b in enumerate(tt_list):
        if b:
            val |= (1 << i)
    return val


# ============================================================
# Exact minimum circuit via DFS enumeration (small N, small s)
# ============================================================

def exact_min_circuit_dfs(target_tt, N, max_gates=20, timeout=120):
    """
    Find minimum circuit for target using iterative deepening.
    Circuit has s gates, each is AND/OR/XOR of two (possibly negated) signals.

    We represent each signal as an integer bitmask (truth table).
    Base signals: x_0,...,x_{N-1} and their negations.
    """
    size = 1 << N
    all_one = (1 << size) - 1
    target = tt_to_int(target_tt)

    # Base signals
    base_signals = []
    for i in range(N):
        tt = 0
        for x in range(size):
            if (x >> i) & 1:
                tt |= (1 << x)
        base_signals.append(tt)

    # Also include negations as free (since we have input negation)
    all_signals = set()
    for s in base_signals:
        all_signals.add(s)
        all_signals.add(all_one ^ s)
    all_signals.add(0)
    all_signals.add(all_one)

    if target in all_signals:
        return 0

    start_time = time.time()

    # Iterative deepening: try s = 1, 2, ...
    for s in range(1, max_gates + 1):
        if time.time() - start_time > timeout:
            return None
        found = _dfs_build(target, all_one, list(all_signals), s, start_time, timeout)
        if found is not None:
            return s

    return None


def _dfs_build(target, all_one, available, gates_left, start_time, timeout):
    """
    DFS: can we build target using gates_left gates from available signals?
    available: list of signal bitmasks we can use as inputs
    """
    if gates_left == 0:
        return None

    if time.time() - start_time > timeout:
        return None

    # Try all pairs of available signals with AND/OR/XOR
    n_avail = len(available)

    for i in range(n_avail):
        for j in range(i, n_avail):
            a, b = available[i], available[j]
            for op in range(3):  # AND, OR, XOR
                if op == 0:
                    res = a & b
                elif op == 1:
                    res = a | b
                else:
                    res = a ^ b

                # Check res and ~res
                for val in [res, all_one ^ res]:
                    if val == target:
                        return True
